/**
 * Harness Core
 *
 * Main orchestration class that combines:
 * - Progress management (cross-session memory)
 * - Feature tracking (task status)
 * - Task routing (model selection)
 * - Agent execution
 */

import { createProgressManager, ProgressManager } from './progress';
import { createFeaturesManager, FeaturesManager } from './features';
import { routeTask, ensureRouterReady, quickClassify } from './router';
import * as ollama from '../clients/ollama';
import * as claudeCode from '../clients/claude-code';
import { getAgent, AGENTS } from '../agents';
import type {
  ChatMessage,
  RouterDecision,
  Feature,
  Model,
  LocalModel,
  CloudModel,
} from '../types';

export interface HarnessConfig {
  projectRoot: string;
  autoRoute?: boolean;
}

export class Harness {
  private progress: ProgressManager;
  private features: FeaturesManager;
  private projectRoot: string;
  private autoRoute: boolean;

  constructor(config: HarnessConfig) {
    this.projectRoot = config.projectRoot;
    this.autoRoute = config.autoRoute ?? true;
    this.progress = createProgressManager(config.projectRoot);
    this.features = createFeaturesManager(config.projectRoot);
  }

  // Initialize harness for a new session
  async startSession(): Promise<void> {
    console.log('Starting harness session...');

    // Ensure router model is ready
    await ensureRouterReady();

    // Log session start
    this.progress.startSession();

    // Show current status
    const stats = this.features.getStats();
    console.log(`Features: ${stats.complete}/${stats.total} complete`);

    const next = this.features.getNextPending();
    if (next) {
      console.log(`Next pending: ${next.id} - ${next.description}`);
